  1	import React from 'react';
  2	import {
  3	  Select,
  4	  SelectOption,
  5	  SelectList,
  6	  SelectOptionProps,
  7	  MenuToggle,
  8	  MenuToggleElement,
  9	  TextInputGroup,
 10	  TextInputGroupMain,
 11	  TextInputGroupUtilities,
 12	  Button,
 13	  Spinner,
 14	} from '@patternfly/react-core';
 15	import { TimesIcon } from '@patternfly/react-icons';
 16	import { useTranslation } from 'react-i18next';
 17	
 18	interface TypeaheadSelectProps {
 19	  id: string;
 20	  width: number;
 21	  placeholder: string;
 22	  options: SelectOptionProps[];
 23	  selected?: string;
 24	  setSelected: (value?: string) => void;
 25	  allowClear?: boolean;
 26	  loading?: boolean;
 27	}
 28	
 29	// adapted from https://v5-archive.patternfly.org/components/menus/select#typeahead
 30	export function TypeaheadSelect(props: TypeaheadSelectProps) {
 31	  const { selected, setSelected } = props;
 32	  const { t } = useTranslation('plugin__distributed-tracing-console-plugin');
 33	  const [isOpen, setIsOpen] = React.useState(false);
 34	  const [inputValue, setInputValue] = React.useState<string>('');
 35	  const [filterValue, setFilterValue] = React.useState<string>('');
 36	  const [selectOptions, setSelectOptions] = React.useState<SelectOptionProps[]>(props.options);
 37	  const [focusedItemIndex, setFocusedItemIndex] = React.useState<number | null>(null);
 38	  const [activeItemId, setActiveItemId] = React.useState<string | null>(null);
 39	  const textInputRef = React.useRef<HTMLInputElement>();
 40	
 41	  const NO_RESULTS = 'no results';
 42	
 43	  React.useEffect(() => {
 44	    let newSelectOptions: SelectOptionProps[] = props.options;
 45	
 46	    // Filter menu items based on the text input value when one exists
 47	    if (filterValue) {
 48	      newSelectOptions = props.options.filter((menuItem) =>
 49	        String(menuItem.children).toLowerCase().includes(filterValue.toLowerCase()),
 50	      );
 51	
 52	      // When no options are found after filtering, display 'No results found'
 53	      if (!newSelectOptions.length) {
 54	        newSelectOptions = [
 55	          {
 56	            isAriaDisabled: true,
 57	            children: t('No results found for {{value}}', { value: filterValue }),
 58	            value: NO_RESULTS,
 59	          },
 60	        ];
 61	      }
 62	
 63	      // Open the menu when the input value changes and the new value is not empty
 64	      if (!isOpen) {
 65	        setIsOpen(true);
 66	      }
 67	    }
 68	
 69	    setSelectOptions(newSelectOptions);
 70	  }, [t, props.options, filterValue, isOpen]);
 71	
 72	  React.useEffect(() => {
 73	    const option = props.options.find((o) => o.value === props.selected);
 74	    if (option) {
 75	      setInputValue(String(option.children));
 76	      setFilterValue('');
 77	    }
 78	  }, [props.selected, props.options]);
 79	
 80	  const createItemId = (value: string) => `${props.id}-item-${value.replace(' ', '-')}`;
 81	
 82	  const setActiveAndFocusedItem = (itemIndex: number) => {
 83	    setFocusedItemIndex(itemIndex);
 84	    const focusedItem = selectOptions[itemIndex];
 85	    setActiveItemId(createItemId(focusedItem.value));
 86	  };
 87	
 88	  const resetActiveAndFocusedItem = () => {
 89	    setFocusedItemIndex(null);
 90	    setActiveItemId(null);
 91	  };
 92	
 93	  const closeMenu = () => {
 94	    setIsOpen(false);
 95	    resetActiveAndFocusedItem();
 96	  };
 97	
 98	  const onInputClick = () => {
 99	    if (!isOpen) {
100	      setIsOpen(true);
101	    } else if (!inputValue) {
102	      closeMenu();
103	    }
104	  };
105	
106	  const selectOption = (value: string | number, content: string | number) => {
107	    setInputValue(String(content));
108	    setFilterValue('');
109	    setSelected(String(value));
110	
111	    closeMenu();
112	  };
113	
114	  const onSelect = (
115	    _event: React.MouseEvent<Element, MouseEvent> | undefined,
116	    value: string | number | undefined,
117	  ) => {
118	    if (value && value !== NO_RESULTS) {
119	      const optionText = selectOptions.find((option) => option.value === value)?.children;
120	      selectOption(value, optionText as string);
121	    }
122	  };
123	
124	  const onTextInputChange = (_event: React.FormEvent<HTMLInputElement>, value: string) => {
125	    setInputValue(value);
126	    setFilterValue(value);
127	
128	    resetActiveAndFocusedItem();
129	
130	    if (value !== selected) {
131	      setSelected('');
132	    }
133	  };
134	
135	  const handleMenuArrowKeys = (key: string) => {
136	    let indexToFocus = 0;
137	
138	    if (!isOpen) {
139	      setIsOpen(true);
140	    }
141	
142	    if (selectOptions.every((option) => option.isDisabled)) {
143	      return;
144	    }
145	
146	    if (key === 'ArrowUp') {
147	      // When no index is set or at the first index, focus to the last, otherwise decrement focus index
148	      if (focusedItemIndex === null || focusedItemIndex === 0) {
149	        indexToFocus = selectOptions.length - 1;
150	      } else {
151	        indexToFocus = focusedItemIndex - 1;
152	      }
153	
154	      // Skip disabled options
155	      while (selectOptions[indexToFocus].isDisabled) {
156	        indexToFocus--;
157	        if (indexToFocus === -1) {
158	          indexToFocus = selectOptions.length - 1;
159	        }
160	      }
161	    }
162	
163	    if (key === 'ArrowDown') {
164	      // When no index is set or at the last index, focus to the first, otherwise increment focus index
165	      if (focusedItemIndex === null || focusedItemIndex === selectOptions.length - 1) {
166	        indexToFocus = 0;
167	      } else {
168	        indexToFocus = focusedItemIndex + 1;
169	      }
170	
171	      // Skip disabled options
172	      while (selectOptions[indexToFocus].isDisabled) {
173	        indexToFocus++;
174	        if (indexToFocus === selectOptions.length) {
175	          indexToFocus = 0;
176	        }
177	      }
178	    }
179	
180	    setActiveAndFocusedItem(indexToFocus);
181	  };
182	
183	  const onInputKeyDown = (event: React.KeyboardEvent<HTMLInputElement>) => {
184	    const focusedItem = focusedItemIndex !== null ? selectOptions[focusedItemIndex] : null;
185	
186	    switch (event.key) {
187	      case 'Enter':
188	        if (
189	          isOpen &&
190	          focusedItem &&
191	          focusedItem.value !== NO_RESULTS &&
192	          !focusedItem.isAriaDisabled
193	        ) {
194	          selectOption(focusedItem.value, focusedItem.children as string);
195	        }
196	
197	        if (!isOpen) {
198	          setIsOpen(true);
199	        }
200	
201	        break;
202	      case 'ArrowUp':
203	      case 'ArrowDown':
204	        event.preventDefault();
205	        handleMenuArrowKeys(event.key);
206	        break;
207	    }
208	  };
209	
210	  const onToggleClick = () => {
211	    setIsOpen(!isOpen);
212	    textInputRef?.current?.focus();
213	  };
214	
215	  const onClearButtonClick = () => {
216	    setSelected('');
217	    setInputValue('');
218	    setFilterValue('');
219	    resetActiveAndFocusedItem();
220	    textInputRef?.current?.focus();
221	  };
222	
223	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
224	    <MenuToggle
225	      ref={toggleRef}
226	      variant="typeahead"
227	      aria-label="Typeahead menu toggle"
228	      onClick={onToggleClick}
229	      isExpanded={isOpen}
230	      style={{ width: props.width }}
231	    >
232	      <TextInputGroup isPlain>
233	        <TextInputGroupMain
234	          value={inputValue}
235	          onClick={onInputClick}
236	          onChange={onTextInputChange}
237	          onKeyDown={onInputKeyDown}
238	          id={`${props.id}-input`}
239	          autoComplete="off"
240	          innerRef={textInputRef}
241	          placeholder={props.placeholder}
242	          {...(activeItemId && { 'aria-activedescendant': activeItemId })}
243	          role="combobox"
244	          isExpanded={isOpen}
245	          aria-controls="select-typeahead-listbox"
246	        />
247	
248	        {props.allowClear && (
249	          <TextInputGroupUtilities {...(!inputValue ? { style: { display: 'none' } } : {})}>
250	            <Button variant="plain" onClick={onClearButtonClick} aria-label="Clear input value">
251	              <TimesIcon aria-hidden />
252	            </Button>
253	          </TextInputGroupUtilities>
254	        )}
255	      </TextInputGroup>
256	    </MenuToggle>
257	  );
258	
259	  return (
260	    <Select
261	      id={props.id}
262	      isOpen={isOpen}
263	      selected={selected}
264	      onSelect={onSelect}
265	      onOpenChange={(isOpen) => {
266	        !isOpen && closeMenu();
267	      }}
268	      toggle={toggle}
269	      shouldFocusFirstItemOnOpen={false}
270	    >
271	      <SelectList id={`${props.id}-listbox`}>
272	        {props.loading ? (
273	          <SelectOption isLoading key="loading" value="loading">
274	            <Spinner size="lg" />
275	          </SelectOption>
276	        ) : (
277	          selectOptions.map((option, index) => (
278	            <SelectOption
279	              key={option.value}
280	              isFocused={focusedItemIndex === index}
281	              className={option.className}
282	              id={createItemId(option.value)}
283	              {...option}
284	              ref={null}
285	            />
286	          ))
287	        )}
288	      </SelectList>
289	    </Select>
290	  );
291	}

